149	/// Parse silks into (base, sequence_number)
150	///
151	/// Silks ending with a 2-digit sequence number are parsed into base and number.
152	/// Format: "foo-bar" -> ("foo-bar", None)
153	///         "foo-bar-01" -> ("foo-bar", Some(1))
154	///         "foo-bar-42" -> ("foo-bar", Some(42))
155	pub fn jjrq_parse_silks_sequence(silks: &str) -> (String, Option<u32>) {
156	    // Use regex ^(.+)-(\d{2})$ for suffix detection
157	    let re = match Regex::new(r"^(.+)-(\d{2})$") {
158	        Ok(r) => r,
159	        Err(_) => {
160	            // Fallback: return full silks as base, no sequence
161	            return (silks.to_string(), None);
162	        }
163	    };
164	
165	    if let Some(caps) = re.captures(silks) {
166	        if let (Some(base_match), Some(num_match)) = (caps.get(1), caps.get(2)) {
167	            let base = base_match.as_str().to_string();
168	            if let Ok(num_str) = num_match.as_str().parse::<u32>() {
169	                return (base, Some(num_str));
170	            }
171	        }
172	    }
173	
174	    // No match: return full silks as base, no sequence
175	    (silks.to_string(), None)
176	}
